   322→/*
   323→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   324→%                                                                             %
   325→%                                                                             %
   326→%                                                                             %
   327→%   G l o b E x p r e s s i o n                                               %
   328→%                                                                             %
   329→%                                                                             %
   330→%                                                                             %
   331→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   332→%
   333→%  GlobExpression() returns MagickTrue if the expression matches the pattern.
   334→%
   335→%  The format of the GlobExpression function is:
   336→%
   337→%      MagickBooleanType GlobExpression(const char *expression,
   338→%        const char *pattern,const MagickBooleanType case_insensitive)
   339→%
   340→%  A description of each parameter follows:
   341→%
   342→%    o expression: Specifies a pointer to a text string containing a file name.
   343→%
   344→%    o pattern: Specifies a pointer to a text string containing a pattern.
   345→%
   346→%    o case_insensitive: set to MagickTrue to ignore the case when matching
   347→%      an expression.
   348→%
   349→*/
   350→MagickExport MagickBooleanType GlobExpression(const char *expression,
   351→  const char *pattern,const MagickBooleanType case_insensitive)
   352→{
   353→  MagickBooleanType
   354→    done,
   355→    match;
   356→
   357→  register const char
   358→    *p;
   359→
   360→  /*
   361→    Return on empty pattern or '*'.
   362→  */
   363→  if (pattern == (char *) NULL)
   364→    return(MagickTrue);
   365→  if (GetUTFCode(pattern) == 0)
   366→    return(MagickTrue);
   367→  if (LocaleCompare(pattern,"*") == 0)
   368→    return(MagickTrue);
   369→  p=pattern+strlen(pattern)-1;
   370→  if ((GetUTFCode(p) == ']') && (strchr(pattern,'[') != (char *) NULL))
   371→    {
   372→      ExceptionInfo
   373→        *exception;
   374→
   375→      ImageInfo
   376→        *image_info;
   377→
   378→      /*
   379→        Determine if pattern is a scene, i.e. img0001.pcd[2].
   380→      */
   381→      image_info=AcquireImageInfo();
   382→      (void) CopyMagickString(image_info->filename,pattern,MagickPathExtent);
   383→      exception=AcquireExceptionInfo();
   384→      (void) SetImageInfo(image_info,0,exception);
   385→      exception=DestroyExceptionInfo(exception);
   386→      if (LocaleCompare(image_info->filename,pattern) != 0)
   387→        {
   388→          image_info=DestroyImageInfo(image_info);
   389→          return(MagickFalse);
   390→        }
   391→      image_info=DestroyImageInfo(image_info);
   392→    }
   393→  /*
   394→    Evaluate glob expression.
   395→  */
   396→  done=MagickFalse;
   397→  while ((GetUTFCode(pattern) != 0) && (done == MagickFalse))
   398→  {
   399→    if (GetUTFCode(expression) == 0)
   400→      if ((GetUTFCode(pattern) != '{') && (GetUTFCode(pattern) != '*'))
   401→        break;
   402→    switch (GetUTFCode(pattern))
   403→    {
   404→      case '*':
   405→      {
   406→        MagickBooleanType
   407→          status;
   408→
   409→        status=MagickFalse;
   410→        pattern+=GetUTFOctets(pattern);
   411→        while ((GetUTFCode(expression) != 0) && (status == MagickFalse))
   412→        {
   413→          status=GlobExpression(expression,pattern,case_insensitive);
   414→          expression+=GetUTFOctets(expression);
   415→        }
   416→        if (status != MagickFalse)
   417→          {
   418→            while (GetUTFCode(expression) != 0)
   419→              expression+=GetUTFOctets(expression);
   420→            while (GetUTFCode(pattern) != 0)
   421→              pattern+=GetUTFOctets(pattern);
   422→          }
   423→        break;
   424→      }
   425→      case '[':
   426→      {
   427→        int
   428→          c;
   429→
   430→        pattern+=GetUTFOctets(pattern);
   431→        for ( ; ; )
   432→        {
   433→          if ((GetUTFCode(pattern) == 0) || (GetUTFCode(pattern) == ']'))
   434→            {
   435→              done=MagickTrue;
   436→              break;
   437→            }
   438→          if (GetUTFCode(pattern) == '\\')
   439→            {
   440→              pattern+=GetUTFOctets(pattern);
   441→              if (GetUTFCode(pattern) == 0)
   442→                {
   443→                  done=MagickTrue;
   444→                  break;
   445→                }
   446→             }
   447→          if (GetUTFCode(pattern+GetUTFOctets(pattern)) == '-')
   448→            {
   449→              c=GetUTFCode(pattern);
   450→              pattern+=GetUTFOctets(pattern);
   451→              pattern+=GetUTFOctets(pattern);
   452→              if (GetUTFCode(pattern) == ']')
   453→                {
   454→                  done=MagickTrue;
   455→                  break;
   456→                }
   457→              if (GetUTFCode(pattern) == '\\')
   458→                {
   459→                  pattern+=GetUTFOctets(pattern);
   460→                  if (GetUTFCode(pattern) == 0)
   461→                    {
   462→                      done=MagickTrue;
   463→                      break;
   464→                    }
   465→                }
   466→              if ((GetUTFCode(expression) < c) ||
   467→                  (GetUTFCode(expression) > GetUTFCode(pattern)))
   468→                {
   469→                  pattern+=GetUTFOctets(pattern);
   470→                  continue;
   471→                }
   472→            }
   473→          else
   474→            if (GetUTFCode(pattern) != GetUTFCode(expression))
   475→              {
   476→                pattern+=GetUTFOctets(pattern);
   477→                continue;
   478→              }
   479→          pattern+=GetUTFOctets(pattern);
   480→          while ((GetUTFCode(pattern) != ']') && (GetUTFCode(pattern) != 0))
   481→          {
   482→            if ((GetUTFCode(pattern) == '\\') &&
   483→                (GetUTFCode(pattern+GetUTFOctets(pattern)) > 0))
   484→              pattern+=GetUTFOctets(pattern);
   485→            pattern+=GetUTFOctets(pattern);
   486→          }
   487→          if (GetUTFCode(pattern) != 0)
   488→            {
   489→              pattern+=GetUTFOctets(pattern);
   490→              expression+=GetUTFOctets(expression);
   491→            }
   492→          break;
   493→        }
   494→        break;
   495→      }
   496→      case '?':
   497→      {
   498→        pattern+=GetUTFOctets(pattern);
   499→        expression+=GetUTFOctets(expression);
   500→        break;
   501→      }
   502→      case '{':
   503→      {
   504→        pattern+=GetUTFOctets(pattern);
   505→        while ((GetUTFCode(pattern) != '}') && (GetUTFCode(pattern) != 0))
   506→        {
   507→          p=expression;
   508→          match=MagickTrue;
   509→          while ((GetUTFCode(p) != 0) && (GetUTFCode(pattern) != 0) &&
   510→                 (GetUTFCode(pattern) != ',') && (GetUTFCode(pattern) != '}') &&
   511→                 (match != MagickFalse))
   512→          {
   513→            if (GetUTFCode(pattern) == '\\')
   514→              pattern+=GetUTFOctets(pattern);
   515→            match=(GetUTFCode(pattern) == GetUTFCode(p)) ? MagickTrue :
   516→              MagickFalse;
   517→            p+=GetUTFOctets(p);
   518→            pattern+=GetUTFOctets(pattern);
   519→          }
   520→          if (GetUTFCode(pattern) == 0)
   521→            {
   522→              match=MagickFalse;
   523→              done=MagickTrue;
   524→              break;
   525→            }
   526→          if (match != MagickFalse)
   527→            {
   528→              expression=p;
   529→              while ((GetUTFCode(pattern) != '}') &&
   530→                     (GetUTFCode(pattern) != 0))
   531→              {
   532→                pattern+=GetUTFOctets(pattern);
   533→                if (GetUTFCode(pattern) == '\\')
   534→                  {
   535→                    pattern+=GetUTFOctets(pattern);
   536→                    if (GetUTFCode(pattern) == '}')
   537→                      pattern+=GetUTFOctets(pattern);
   538→                  }
   539→              }
   540→            }
   541→          else
   542→            {
   543→              while ((GetUTFCode(pattern) != '}') &&
   544→                     (GetUTFCode(pattern) != ',') &&
   545→                     (GetUTFCode(pattern) != 0))
   546→              {
   547→                pattern+=GetUTFOctets(pattern);
   548→                if (GetUTFCode(pattern) == '\\')
   549→                  {
   550→                    pattern+=GetUTFOctets(pattern);
   551→                    if ((GetUTFCode(pattern) == '}') ||
   552→                        (GetUTFCode(pattern) == ','))
   553→                      pattern+=GetUTFOctets(pattern);
   554→                  }
   555→              }
   556→            }
   557→            if (GetUTFCode(pattern) != 0)
   558→              pattern+=GetUTFOctets(pattern);
   559→          }
   560→        break;
   561→      }
   562→      case '\\':
   563→      {
   564→        pattern+=GetUTFOctets(pattern);
   565→        if (GetUTFCode(pattern) == 0)
   566→          break;
   567→      }
   568→      default:
   569→      {
   570→        if (case_insensitive != MagickFalse)
   571→          {
   572→            if (tolower((int) GetUTFCode(expression)) !=
   573→                tolower((int) GetUTFCode(pattern)))
   574→              {
   575→                done=MagickTrue;
   576→                break;
   577→              }
   578→          }
   579→        else
   580→          if (GetUTFCode(expression) != GetUTFCode(pattern))
   581→            {
   582→              done=MagickTrue;
   583→              break;
   584→            }
   585→        expression+=GetUTFOctets(expression);
   586→        pattern+=GetUTFOctets(pattern);
   587→      }
   588→    }
   589→  }
   590→  while (GetUTFCode(pattern) == '*')
   591→    pattern+=GetUTFOctets(pattern);
   592→  match=(GetUTFCode(expression) == 0) && (GetUTFCode(pattern) == 0) ?
   593→    MagickTrue : MagickFalse;
   594→  return(match);
   595→}
