   597→/*
   598→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   599→%                                                                             %
   600→%                                                                             %
   601→%                                                                             %
   602→+     I s G l o b                                                             %
   603→%                                                                             %
   604→%                                                                             %
   605→%                                                                             %
   606→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   607→%
   608→%  IsGlob() returns MagickTrue if the path specification contains a globbing
   609→%  pattern.
   610→%
   611→%  The format of the IsGlob method is:
   612→%
   613→%      MagickBooleanType IsGlob(const char *geometry)
   614→%
   615→%  A description of each parameter follows:
   616→%
   617→%    o path: the path.
   618→%
   619→*/
   620→MagickPrivate MagickBooleanType IsGlob(const char *path)
   621→{
   622→  MagickBooleanType
   623→    status = MagickFalse;
   624→
   625→  register const char
   626→    *p;
   627→
   628→  if (IsPathAccessible(path) != MagickFalse)
   629→    return(MagickFalse);
   630→  for (p=path; *p != '\0'; p++)
   631→  {
   632→    switch (*p)
   633→    {
   634→      case '*':
   635→      case '?':
   636→      case '{':
   637→      case '}':
   638→      case '[':
   639→      case ']':
   640→      {
   641→        status=MagickTrue;
   642→        break;
   643→      }
   644→      default:
   645→        break;
   646→    }
   647→  }
   648→  return(status);
   649→}
