   651→/*
   652→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   653→%                                                                             %
   654→%                                                                             %
   655→%                                                                             %
   656→%   T o k e n i z e r                                                         %
   657→%                                                                             %
   658→%                                                                             %
   659→%                                                                             %
   660→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   661→%
   662→%  Tokenizer() is a generalized, finite state token parser.  It extracts tokens
   663→%  one at a time from a string of characters.  The characters used for white
   664→%  space, for break characters, and for quotes can be specified.  Also,
   665→%  characters in the string can be preceded by a specifiable escape character
   666→%  which removes any special meaning the character may have.
   667→%
   668→%  Here is some terminology:
   669→%
   670→%    o token: A single unit of information in the form of a group of
   671→%      characters.
   672→%
   673→%    o white space: Apace that gets ignored (except within quotes or when
   674→%      escaped), like blanks and tabs. in addition, white space terminates a
   675→%      non-quoted token.
   676→%
   677→%    o break set: One or more characters that separates non-quoted tokens.
   678→%      Commas are a common break character. The usage of break characters to
   679→%      signal the end of a token is the same as that of white space, except
   680→%      multiple break characters with nothing or only white space between
   681→%      generate a null token for each two break characters together.
   682→%
   683→%      For example, if blank is set to be the white space and comma is set to
   684→%      be the break character, the line
   685→%
   686→%        A, B, C ,  , DEF
   687→%
   688→%        ... consists of 5 tokens:
   689→%
   690→%        1)  "A"
   691→%        2)  "B"
   692→%        3)  "C"
   693→%        4)  "" (the null string)
   694→%        5)  "DEF"
   695→%
   696→%    o Quote character: A character that, when surrounding a group of other
   697→%      characters, causes the group of characters to be treated as a single
   698→%      token, no matter how many white spaces or break characters exist in
   699→%      the group. Also, a token always terminates after the closing quote.
   700→%      For example, if ' is the quote character, blank is white space, and
   701→%      comma is the break character, the following string
   702→%
   703→%        A, ' B, CD'EF GHI
   704→%
   705→%        ... consists of 4 tokens:
   706→%
   707→%        1)  "A"
   708→%        2)  " B, CD" (note the blanks & comma)
   709→%        3)  "EF"
   710→%        4)  "GHI"
   711→%
   712→%      The quote characters themselves do not appear in the resultant
   713→%      tokens.  The double quotes are delimiters i use here for
   714→%      documentation purposes only.
   715→%
   716→%    o Escape character: A character which itself is ignored but which
   717→%      causes the next character to be used as is.  ^ and \ are often used
   718→%      as escape characters. An escape in the last position of the string
   719→%      gets treated as a "normal" (i.e., non-quote, non-white, non-break,
   720→%      and non-escape) character. For example, assume white space, break
   721→%      character, and quote are the same as in the above examples, and
   722→%      further, assume that ^ is the escape character. Then, in the string
   723→%
   724→%        ABC, ' DEF ^' GH' I ^ J K^ L ^
   725→%
   726→%        ... there are 7 tokens:
   727→%
   728→%        1)  "ABC"
   729→%        2)  " DEF ' GH"
   730→%        3)  "I"
   731→%        4)  " "     (a lone blank)
   732→%        5)  "J"
   733→%        6)  "K L"
   734→%        7)  "^"     (passed as is at end of line)
   735→%
   736→%  The format of the Tokenizer method is:
   737→%
   738→%      int Tokenizer(TokenInfo *token_info,const unsigned flag,char *token,
   739→%        const size_t max_token_length,const char *line,const char *white,
   740→%        const char *break_set,const char *quote,const char escape,
   741→%        char *breaker,int *next,char *quoted)
   742→%
   743→%  A description of each parameter follows:
   744→%
   745→%    o flag: right now, only the low order 3 bits are used.
   746→%
   747→%        1 => convert non-quoted tokens to upper case
   748→%        2 => convert non-quoted tokens to lower case
   749→%        0 => do not convert non-quoted tokens
   750→%
   751→%    o token: a character string containing the returned next token
   752→%
   753→%    o max_token_length: the maximum size of "token".  Characters beyond
   754→%      "max_token_length" are truncated.
   755→%
   756→%    o string: the string to be parsed.
   757→%
   758→%    o white: a string of the valid white spaces.  example:
   759→%
   760→%        char whitesp[]={" \t"};
   761→%
   762→%      blank and tab will be valid white space.
   763→%
   764→%    o break: a string of the valid break characters. example:
   765→%
   766→%        char breakch[]={";,"};
   767→%
   768→%      semicolon and comma will be valid break characters.
   769→%
   770→%    o quote: a string of the valid quote characters. An example would be
   771→%
   772→%        char whitesp[]={"'\"");
   773→%
   774→%      (this causes single and double quotes to be valid) Note that a
   775→%      token starting with one of these characters needs the same quote
   776→%      character to terminate it.
   777→%
   778→%      for example:
   779→%
   780→%        "ABC '
   781→%
   782→%      is unterminated, but
   783→%
   784→%        "DEF" and 'GHI'
   785→%
   786→%      are properly terminated.  Note that different quote characters
   787→%      can appear on the same line; only for a given token do the quote
   788→%      characters have to be the same.
   789→%
   790→%    o escape: the escape character (NOT a string ... only one
   791→%      allowed). Use zero if none is desired.
   792→%
   793→%    o breaker: the break character used to terminate the current
   794→%      token.  If the token was quoted, this will be the quote used.  If
   795→%      the token is the last one on the line, this will be zero.
   796→%
   797→%    o next: this variable points to the first character of the
   798→%      next token.  it gets reset by "tokenizer" as it steps through the
   799→%      string.  Set it to 0 upon initialization, and leave it alone
   800→%      after that.  You can change it if you want to jump around in the
   801→%      string or re-parse from the beginning, but be careful.
   802→%
   803→%    o quoted: set to True if the token was quoted and MagickFalse
   804→%      if not.  You may need this information (for example:  in C, a
   805→%      string with quotes around it is a character string, while one
   806→%      without is an identifier).
   807→%
   808→%    o result: 0 if we haven't reached EOS (end of string), and 1
   809→%      if we have.
   810→%
   811→*/
   812→
   813→#define IN_WHITE 0
   814→#define IN_TOKEN 1
   815→#define IN_QUOTE 2
   816→#define IN_OZONE 3
   817→
   818→static ssize_t sindex(int c,const char *string)
   819→{
   820→  register const char
   821→    *p;
   822→
   823→  for (p=string; *p != '\0'; p++)
   824→    if (c == (int) (*p))
   825→      return((ssize_t) (p-string));
   826→  return(-1);
   827→}
   828→
   829→static void StoreToken(TokenInfo *token_info,char *string,
   830→  size_t max_token_length,int c)
   831→{
   832→  register ssize_t
   833→    i;
   834→
   835→  if ((token_info->offset < 0) ||
   836→      ((size_t) token_info->offset >= (max_token_length-1)))
   837→    return;
   838→  i=token_info->offset++;
   839→  string[i]=(char) c;
   840→  if (token_info->state == IN_QUOTE)
   841→    return;
   842→  switch (token_info->flag & 0x03)
   843→  {
   844→    case 1:
   845→    {
   846→      string[i]=(char) toupper(c);
   847→      break;
   848→    }
   849→    case 2:
   850→    {
   851→      string[i]=(char) tolower(c);
   852→      break;
   853→    }
   854→    default:
   855→      break;
   856→  }
   857→}
   858→
   859→MagickExport int Tokenizer(TokenInfo *token_info,const unsigned flag,
   860→  char *token,const size_t max_token_length,const char *line,const char *white,
   861→  const char *break_set,const char *quote,const char escape,char *breaker,
   862→  int *next,char *quoted)
   863→{
   864→  int
   865→    c;
   866→
   867→  register ssize_t
   868→    i;
   869→
   870→  *breaker='\0';
   871→  *quoted='\0';
