   361→        }
   362→      p+=GetPixelChannels(image);
   363→    }
   364→    if (SyncCacheViewAuthenticPixels(chop_view,exception) == MagickFalse)
   365→      status=MagickFalse;
   366→    if (image->progress_monitor != (MagickProgressMonitor) NULL)
   367→      {
   368→        MagickBooleanType
